ALTER TABLE `users` ADD `latitude` decimal(10,8);
ALTER TABLE `users` ADD `longitude` decimal(11,8);
ALTER TABLE `users` ADD CONSTRAINT `users_phone_unique` UNIQUE(`phone`);
